import { memo } from 'react'
import { useDraggable } from '@dnd-kit/core'
import { useRef } from 'react'
import type { Player, Mode } from '@/store/types'
import { lightenColour } from '@/utils/colour'

interface PlayerTokenProps {
  player: Player
  colour: string
  isSelected: boolean
  onSelect: () => void
  onEdit: () => void
  svgRef: React.RefObject<SVGSVGElement | null>
  mode: Mode
}

function PlayerToken({
  player, colour, isSelected, onSelect, onEdit, svgRef, mode,
}: PlayerTokenProps) {
  const { attributes, listeners, setNodeRef, transform, isDragging } = useDraggable({
    id: player.id,
    disabled: mode === 'draw-arrow',
  })

  const svg = svgRef.current
  const rect = svg?.getBoundingClientRect()
  const scaleX = rect ? 680 / rect.width : 1
  const scaleY = rect ? 1050 / rect.height : 1

  const dx = transform ? transform.x * scaleX : 0
  const dy = transform ? transform.y * scaleY : 0

  const VB_W = 680
  const VB_H = 1050

  const rawX = player.x + dx
  const rawY = player.y + dy
  const clampedX = isDragging ? Math.max(16, Math.min(VB_W - 16, rawX)) : rawX
  const clampedY = isDragging ? Math.max(16, Math.min(VB_H - 16, rawY)) : rawY

  const shortName = player.name.length > 8 ? player.name.slice(0, 7) + '…' : player.name
  const lastTouchTapTs = useRef(0)

  function maybeHandleDoubleTap(e: React.PointerEvent<SVGGElement>) {
    if (e.pointerType !== 'touch' || mode === 'draw-arrow' || isDragging) return
    const now = Date.now()
    if (now - lastTouchTapTs.current < 320) {
      e.stopPropagation()
      onEdit()
    }
    lastTouchTapTs.current = now
  }

  return (
    <g
      ref={setNodeRef as (el: SVGGElement | null) => void}
      transform={`translate(${clampedX}, ${clampedY}) ${isDragging ? 'scale(1.15)' : ''}`}
      style={{
        cursor: isDragging ? 'grabbing' : (mode === 'draw-arrow' ? 'crosshair' : 'grab'),
        filter: isDragging ? 'drop-shadow(0 8px 16px rgba(0,0,0,0.6))' : undefined,
        transition: isDragging ? 'none' : 'transform 150ms ease',
        touchAction: 'none',
      }}
      onClick={(e) => {
        if (mode === 'draw-arrow') return
        e.stopPropagation()
        onSelect()
      }}
      onDoubleClick={(e) => {
        if (mode === 'draw-arrow') return
        e.stopPropagation()
        onEdit()
      }}
      onPointerUp={maybeHandleDoubleTap}
      {...attributes}
      {...(mode === 'select' ? listeners : {})}
    >
      {/* Per-token SVG defs — IDs namespaced to prevent DOM collisions across 22 tokens */}
      <defs>
        <radialGradient id={`grad-${player.id}`} cx="40%" cy="35%" r="65%">
          <stop offset="0%" stopColor={lightenColour(colour, 0.25)} />
          <stop offset="100%" stopColor={colour} />
        </radialGradient>
        <filter id={`shadow-${player.id}`} x="-30%" y="-30%" width="160%" height="160%">
          <feDropShadow dx="0" dy="3" stdDeviation="3" floodOpacity="0.4" />
        </filter>
        <filter id={`glow-${player.id}`} x="-50%" y="-50%" width="200%" height="200%">
          <feDropShadow dx="0" dy="0" stdDeviation="6" floodColor={colour} floodOpacity="0.85" />
        </filter>
      </defs>

      {/* Token body — stroke is unconditional; selection is communicated via glow filter only.
          Drag shadow is handled by the <g> style above — no isDragging branch needed here. */}
      <circle
        r={16}
        fill={`url(#grad-${player.id})`}
        stroke="rgba(255,255,255,0.6)"
        strokeWidth={1.5}
        filter={isSelected ? `url(#glow-${player.id})` : `url(#shadow-${player.id})`}
      />

      {/* Inner shimmer ring */}
      <circle r={12} fill="none" stroke="rgba(255,255,255,0.12)" strokeWidth={1} />

      {/* Position label */}
      <text
        fontSize={11}
        fontWeight={800}
        fontFamily="Inter, sans-serif"
        fill="white"
        textAnchor="middle"
        dominantBaseline="central"
        style={{ pointerEvents: 'none', userSelect: 'none' }}
      >
        {player.position}
      </text>

      {/* Player name */}
      <text
        y={25}
        fontSize={9}
        fontWeight={500}
        fontFamily="Inter, sans-serif"
        fill="rgba(255,255,255,0.9)"
        textAnchor="middle"
        dominantBaseline="hanging"
        style={{ pointerEvents: 'none', userSelect: 'none' }}
      >
        {shortName}
      </text>
    </g>
  )
}

PlayerToken.displayName = 'PlayerToken'
export default memo(PlayerToken)

import { useState, useEffect } from 'react'
import { useBoardStore } from '@/store/boardStore'
import type { SavedFormation } from '@/store/types'

export default function SaveLoadModal() {
  const isOpen           = useBoardStore((s) => s.isSaveLoadModalOpen)
  const toggleModal      = useBoardStore((s) => s.toggleSaveLoadModal)
  const saveToLocal      = useBoardStore((s) => s.saveToLocalStorage)
  const loadFromLocal    = useBoardStore((s) => s.loadFromLocalStorage)
  const deleteSave       = useBoardStore((s) => s.deleteSave)
  const listSaves        = useBoardStore((s) => s.listSaves)
  const clearArrows      = useBoardStore((s) => s.clearArrows)
  const clearBoard       = useBoardStore((s) => s.clearBoard)

  const [saveName, setSaveName] = useState('')
  const [saves, setSaves] = useState<SavedFormation[]>([])
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null)

  useEffect(() => {
    if (isOpen) setSaves(listSaves())
  }, [isOpen, listSaves])

  if (!isOpen) return null

  function handleSave() {
    if (!saveName.trim()) return
    saveToLocal(saveName.trim())
    setSaves(listSaves())
    setSaveName('')
  }

  function handleLoad(name: string) {
    loadFromLocal(name)
    toggleModal()
  }

  function handleDelete(name: string) {
    deleteSave(name)
    setSaves(listSaves())
    setConfirmDelete(null)
  }

  return (
    <div
      className="fixed inset-0 flex items-center justify-center z-50"
      style={{ background: 'rgba(0,0,0,0.6)', animation: 'modal-bg-in 200ms ease' }}
      onClick={toggleModal}
    >
      <div
        className="rounded-xl shadow-2xl w-full max-w-md mx-4 flex flex-col"
        style={{
          maxHeight: '70vh',
          background: 'var(--bg-panel)',
          border: '1px solid var(--border)',
          color: 'var(--text-primary)',
          fontFamily: 'DM Mono, monospace',
          animation: 'modal-in 200ms cubic-bezier(0.4, 0, 0.2, 1)',
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4" style={{ borderBottom: '1px solid var(--border)' }}>
          <span className="font-medium text-sm">Saves</span>
          <button
            onClick={toggleModal}
            aria-label="Close"
            style={{ color: 'var(--text-secondary)', fontSize: 20, lineHeight: 1, cursor: 'pointer' }}
          >×</button>
        </div>

        {/* Save row */}
        <div className="flex gap-2 p-4" style={{ borderBottom: '1px solid var(--border)' }}>
          <input
            className="flex-1 rounded px-3 py-2 text-xs"
            style={{
              background: 'var(--bg-app)',
              border: '1px solid var(--border)',
              color: 'var(--text-primary)',
              fontFamily: 'inherit',
            }}
            placeholder="Save name..."
            value={saveName}
            onChange={(e) => setSaveName(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') handleSave(); e.stopPropagation() }}
          />
          <button
            className="px-4 py-2 rounded text-xs font-medium"
            style={{ background: 'var(--accent)', color: 'white' }}
            onClick={handleSave}
          >
            Save
          </button>
        </div>

        {/* Footer actions */}
        <div className="flex gap-2 p-4" style={{ borderBottom: '1px solid var(--border)' }}>
          <button
            className="flex-1 px-3 py-2 rounded text-xs font-medium"
            style={{ background: 'transparent', border: '1px solid var(--border)', color: 'var(--text-secondary)', cursor: 'pointer' }}
            onClick={() => {
              if (window.confirm('Clear all arrows? This cannot be undone.')) {
                clearArrows()
              }
            }}
          >
            Clear arrows
          </button>
          <button
            className="flex-1 px-3 py-2 rounded text-xs font-medium"
            style={{ background: '#dc2626', color: 'white', border: 'none', cursor: 'pointer' }}
            onClick={() => {
              if (window.confirm('Reset board to default 4-3-3? All changes will be lost.')) {
                clearBoard()
                toggleModal()
              }
            }}
          >
            Reset board
          </button>
        </div>

        {/* List */}
        <div className="flex-1 overflow-y-auto p-2">
          {saves.length === 0 && (
            <p className="p-4 text-center text-xs" style={{ color: 'var(--text-secondary)' }}>No saves yet</p>
          )}
          {saves.slice().reverse().map((s) => (
            <div
              key={s.name}
              className="flex items-center justify-between rounded-lg p-3 mb-1"
              style={{ background: 'var(--bg-app)' }}
            >
              <div>
                <p className="text-xs font-medium">{s.name}</p>
                <p className="text-xs" style={{ color: 'var(--text-secondary)' }}>
                  {new Date(s.savedAt).toLocaleDateString()} {new Date(s.savedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
              <div className="flex gap-1">
                <button
                  className="px-2 py-1 rounded text-xs"
                  style={{ background: 'var(--accent)', color: 'white' }}
                  onClick={() => handleLoad(s.name)}
                >
                  Load
                </button>
                {confirmDelete === s.name ? (
                  <button
                    className="px-2 py-1 rounded text-xs"
                    style={{ background: '#dc2626', color: 'white' }}
                    onClick={() => handleDelete(s.name)}
                  >
                    Confirm
                  </button>
                ) : (
                  <button
                    className="px-2 py-1 rounded text-xs"
                    style={{ border: '1px solid var(--border)', color: 'var(--text-secondary)' }}
                    onClick={() => setConfirmDelete(s.name)}
                  >
                    ×
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect, useRef } from 'react'
import { useBoardStore } from '@/store/boardStore'
import type { Player, PositionLabel } from '@/store/types'

const POSITIONS: PositionLabel[] = [
  'GK',
  'RB', 'LB', 'CB', 'RCB', 'LCB', 'RWB', 'LWB',
  'CDM', 'CM', 'RCM', 'LCM', 'CAM', 'DM',
  'RW', 'LW', 'RAM', 'LAM',
  'CF', 'ST', 'SS',
]

interface PlayerEditPopoverProps {
  player: Player
  svgRef: React.RefObject<SVGSVGElement | null>
  onClose: () => void
}

export default function PlayerEditPopover({ player, svgRef, onClose }: PlayerEditPopoverProps) {
  const updatePlayer = useBoardStore((s) => s.updatePlayer)
  const removePlayer = useBoardStore((s) => s.removePlayer)
  const selectPlayer = useBoardStore((s) => s.selectPlayer)

  const [name, setName] = useState(player.name)
  const [position, setPosition] = useState<PositionLabel>(player.position)
  const popoverRef = useRef<HTMLDivElement>(null)

  // Sync fields when player changes
  useEffect(() => {
    setName(player.name)
    setPosition(player.position)
  }, [player.id, player.name, player.position])

  // Close on click outside
  useEffect(() => {
    function handler(e: MouseEvent) {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        applyChanges()
        selectPlayer(null)
        onClose()
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  })

  function applyChanges() {
    updatePlayer(player.id, { name, position })
  }

  // Calculate position relative to the SVG element
  const svg = svgRef.current
  const svgRect = svg?.getBoundingClientRect()
  const containerRect = svg?.parentElement?.getBoundingClientRect()

  if (!svgRect || !containerRect) return null

  const scaleX = svgRect.width / 680
  const scaleY = svgRect.height / 1050
  const screenX = (svgRect.left - containerRect.left) + player.x * scaleX
  const screenY = (svgRect.top  - containerRect.top)  + player.y * scaleY

  // Offset the popover so it appears above/beside the token
  const POPOVER_W = 160
  const POPOVER_H = 200

  const popLeft = Math.max(
    4,
    Math.min(
      screenX - POPOVER_W / 2,
      (containerRect?.width ?? 400) - POPOVER_W - 4
    )
  )

  const popTop = Math.max(
    4,
    Math.min(
      screenY - POPOVER_H - 20,
      (containerRect?.height ?? 600) - POPOVER_H - 4
    )
  )

  return (
    <div
      ref={popoverRef}
      className="absolute z-50 rounded-lg shadow-xl p-3 w-40"
      style={{
        left: popLeft,
        top:  popTop,
        backgroundColor: 'var(--bg-toolbar)',
        border: '1px solid var(--border)',
        color: 'var(--text-primary)',
        fontFamily: 'DM Mono, monospace',
        fontSize: 12,
      }}
      onClick={(e) => e.stopPropagation()}
    >
      <div className="mb-2">
        <label className="block mb-1" style={{ color: 'var(--text-secondary)', fontSize: 10 }}>NAME</label>
        <input
          className="w-full rounded px-2 py-1 text-xs"
          style={{
            background: 'var(--bg-app)',
            border: '1px solid var(--border)',
            color: 'var(--text-primary)',
            fontFamily: 'inherit',
          }}
          value={name}
          onChange={(e) => setName(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') { applyChanges(); selectPlayer(null); onClose() }
            if (e.key === 'Escape') { selectPlayer(null); onClose() }
            e.stopPropagation()
          }}
          autoFocus
        />
      </div>
      <div className="mb-3">
        <label className="block mb-1" style={{ color: 'var(--text-secondary)', fontSize: 10 }}>POSITION</label>
        <select
          className="w-full rounded px-2 py-1 text-xs"
          style={{
            background: 'var(--bg-app)',
            border: '1px solid var(--border)',
            color: 'var(--text-primary)',
            fontFamily: 'inherit',
          }}
          value={position}
          onChange={(e) => {
            const p = e.target.value as PositionLabel
            setPosition(p)
            updatePlayer(player.id, { position: p })
          }}
        >
          {POSITIONS.map((p) => <option key={p} value={p}>{p}</option>)}
        </select>
      </div>
      <button
        className="w-full rounded py-1 text-xs font-medium"
        style={{ background: '#dc2626', color: 'white' }}
        onClick={() => { removePlayer(player.id); selectPlayer(null); onClose() }}
      >
        Remove
      </button>
    </div>
  )
}
